 47→const ensureJsonLd = (id, payload) => {
 48→  let element = document.getElementById(id);
 49→  if (!element) {
 50→    element = document.createElement("script");
 51→    element.id = id;
 52→    element.type = "application/ld+json";
 53→    document.head.appendChild(element);
 54→  }
 55→
 56→  element.textContent = JSON.stringify(payload);
